    return null;
  }

  return {
    displayName: match[1].trim(),
    studentId: match[2].trim(),
  };
}

function parseCoursesFromPage() {
  const lines = document.body.innerText
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line.length > 0);

  const courses = [];

  for (let i = 0; i < lines.length; i++) {
